    parts = desc.split(" in ")
    if len(parts) > 1:
        location_part = parts[-1]
        loc_segments = location_part.split(',')
        if len(loc_segments) >= 2:
            potential_state = loc_segments[1].strip()
            state_tokens = potential_state.split()
            if len(state_tokens) > 0:
                token = state_tokens[0]
                if len(token) == 2 and token.isupper():
                    state = token

    if bid in debug_ids:
        print(f"Debug {bid}: State found = {state}, Desc = {desc[:50]}...")

    if state:
        state_counts[state] = state_counts.get(state, 0) + 1
        if state == "MO":
            found_ids.append(bid)

print(f"Total MO businesses found: {len(found_ids)}")
print(f"Sample MO businesses: {found_ids[:10]}")

